options.afterRender:
function safe(value) {
  return value === undefined || value === null || value === ""
    ? "-"
    : value;
}

function css(value) {
  return String(safe(value))
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-");
}

function badge(value, prefix) {
  value = safe(value);
  const className = prefix === "quality" && value === "-" ? "quality-unknown" : prefix + "-" + css(value);
  return '<span class="badge ' + className + '">' + value + '</span>';
}

function stateBadges(device) {
  let html = badge(device.state, "state");
  if (device.trip) html += '<span class="badge event-trip">TRIP</span>';
  if (device.alarm) html += '<span class="badge event-alarm">ALARM</span>';
  return html;
}

function buildPackages(state) {

  const packages = [];

  // ======================
  // Chillers
  // ======================

  Object.values(state.chillers || {}).forEach(ch => {

    packages.push({
      name: ch.chillerId.toUpperCase(),
      state: ch.state,
      controlMode: ch.controlMode,
      availability: ch.availability,
      reason: ch.reason,
      devices: [

        {
          type: "Chiller",
          id: ch.chiller.deviceId,
          mode: ch.chiller.mode,
          remote: ch.chiller.remoteMode,
          state: ch.chiller.state,
          trip: ch.chiller.trip,
          alarm: ch.chiller.alarm,
          quality: ch.chiller.telemetryQuality,
          reason: ch.chiller.reason
        },

        {
          type: "CHW Pump",
          id: ch.chwPump.deviceId,
          mode: ch.chwPump.mode,
          remote: ch.chwPump.remoteMode,
          state: ch.chwPump.state,
          trip: ch.chwPump.trip,
          alarm: ch.chwPump.alarm,
          quality: ch.chwPump.telemetryQuality,
          reason: ch.chwPump.reason
        },

        {
          type: "CW Pump",
          id: ch.cwPump.deviceId,
          mode: ch.cwPump.mode,
          remote: ch.cwPump.remoteMode,
          state: ch.cwPump.state,
          trip: ch.cwPump.trip,
          alarm: ch.cwPump.alarm,
          quality: ch.cwPump.telemetryQuality,
          reason: ch.cwPump.reason
        }

      ]
    });

  });

  // ======================
  // Cooling Towers
  // ======================

  Object.values(state.coolingTowers || {}).forEach(ct => {

    const devices = [];

    devices.push({
      type: "Cooling Tower",
      id: ct.towerId,
      mode: ct.controlMode,
      remote: ct.remoteMode,
      state: ct.state,
      trip: false,
      alarm: false,
      quality: "-",
      reason: "-"
    });

    (ct.fans || []).forEach((fan, i) => {

      devices.push({
        type: "Fan " + (i + 1),
        id: fan.deviceId,
        mode: fan.mode,
        remote: fan.remoteMode,
        state: fan.state,
        trip: fan.trip,
        alarm: fan.alarm,
        quality: fan.telemetryQuality,
        reason: fan.reason
      });

    });

    (ct.valves || []).forEach((valve, i) => {

      devices.push({
        type: i === 0 ? "Inlet Valve" : "Outlet Valve",
        id: valve.deviceId,
        mode: valve.mode,
        remote: valve.remoteMode,
        state: valve.state,
        trip: valve.trip,
        alarm: valve.alarm,
        quality: valve.telemetryQuality,
        reason: valve.reason
      });

    });

    packages.push({
      name: ct.towerId.toUpperCase(),
      state: ct.state,
      controlMode: ct.controlMode,
      availability: ct.availability,
      reason: ct.reason,
      devices
    });

  });

  return packages;
}

function renderDeviceStateTable(state) {

  const packages = buildPackages(state);

  let html = '' +
    '<table class="device-table">' +
      '<thead>' +
        '<tr>' +
          '<th>Package</th>' +
          '<th>Pkg State</th>' +
          '<th>Control</th>' +
          '<th>Availability</th>' +
          '<th>Pkg Reason</th>' +
          '<th>Device</th>' +
          '<th>ID</th>' +
          '<th>Mode</th>' +
          '<th>Remote</th>' +
          '<th>State</th>' +
          '<th>Quality</th>' +
          '<th>Device Reason</th>' +
        '</tr>' +
      '</thead>' +
      '<tbody>';

  packages.forEach(pkg => {

    pkg.devices.forEach((device, index) => {

      html += '<tr>';

      if (index === 0) {

        html += '' +
          '<td rowspan="' + pkg.devices.length + '" class="package-cell">' + pkg.name + '</td>' +
          '<td rowspan="' + pkg.devices.length + '" class="package-info-cell">' + badge(pkg.state, "state") + '</td>' +
          '<td rowspan="' + pkg.devices.length + '" class="package-info-cell">' + badge(pkg.controlMode, "mode") + '</td>' +
          '<td rowspan="' + pkg.devices.length + '" class="package-info-cell">' + badge(pkg.availability, "availability") + '</td>' +
          '<td rowspan="' + pkg.devices.length + '" class="package-reason-cell muted">' + safe(pkg.reason) + '</td>';

      }

      html += '' +
        '<td>' + device.type + '</td>' +
        '<td>' + device.id + '</td>' +
        '<td>' + badge(device.mode, "mode") + '</td>' +
        '<td>' + badge(device.remote, "remote") + '</td>' +
        '<td class="state-cell">' + stateBadges(device) + '</td>' +
        '<td>' + badge(device.quality, "quality") + '</td>' +
        '<td class="muted">' + safe(device.reason) + '</td>';

      html += '</tr>';

    });

  });

  html += '</tbody></table>';

  document.getElementById("device-state-table").innerHTML = html;
  document.getElementById("device-state-ts").innerHTML = "Last updated: " + new Date(state.timestamp).toLocaleString();
}

// Usage:
// renderDeviceStateTable(latestState);
renderDeviceStateTable(context.data);

options.styles:
#cpms-device-state {
    font-family: Arial, sans-serif;
}

#cpms-device-state .device-table {
    width: 100%;
    border-collapse: collapse;
    background: #fff;
    font-size: 13px;
}

#cpms-device-state .device-table th,
#cpms-device-state .device-table td {
    padding: 8px 10px;
    border: 1px solid #ddd;
    text-align: left;
    vertical-align: middle;
}

#cpms-device-state .device-table th {
    background: #f1f5f9;
    font-weight: 600;
}

#cpms-device-state .package-cell {
    background: #f8fafc;
    font-weight: bold;
    white-space: nowrap;
}

#cpms-device-state .package-info-cell,
#cpms-device-state .package-reason-cell {
    background: #f8fafc;
}

#cpms-device-state .package-reason-cell {
    min-width: 140px;
}

#cpms-device-state .badge {
    display: inline-block;
    min-width: 64px;
    padding: 3px 8px;
    border-radius: 999px;
    font-size: 11px;
    font-weight: 600;
    text-align: center;
}

/* ---------- State ---------- */

#cpms-device-state .state-off {
    background: #e5e7eb;
    color: #374151;
}

#cpms-device-state .state-on,
#cpms-device-state .state-running {
    background: #dcfce7;
    color: #166534;
}

#cpms-device-state .state-starting {
    background: #dbeafe;
    color: #1d4ed8;
}

#cpms-device-state .state-stopping {
    background: #fde68a;
    color: #92400e;
}

#cpms-device-state .state-fault,
#cpms-device-state .state-alarm,
#cpms-device-state .state-lockout {
    background: #fee2e2;
    color: #991b1b;
}

#cpms-device-state .state-cell .badge + .badge {
    margin-left: 4px;
}

#cpms-device-state .event-trip {
    background: #991b1b;
    color: #fff;
}

#cpms-device-state .event-alarm {
    background: #f59e0b;
    color: #111827;
}

/* ---------- Mode ---------- */

#cpms-device-state .mode-auto,
#cpms-device-state .remote-auto {
    background: #dbeafe;
    color: #1d4ed8;
}

#cpms-device-state .mode-manual,
#cpms-device-state .remote-manual {
    background: #fef3c7;
    color: #92400e;
}

/* ---------- Availability ---------- */

#cpms-device-state .availability-available {
    background: #dcfce7;
    color: #166534;
}

#cpms-device-state .availability-maintenance {
    background: #fef7e2;
    color: #99791b;
}

#cpms-device-state .availability-unavailable {
    background: #fee2e2;
    color: #991b1b;
}


/* ---------- Quality ---------- */

#cpms-device-state .quality-good {
    background: #dcfce7;
    color: #166534;
}

#cpms-device-state .quality-stale,
#cpms-device-state .quality-insufficient,
#cpms-device-state .quality-fair {
    background: #fef3c7;
    color: #92400e;
}

#cpms-device-state .quality-missing,
#cpms-device-state .quality-bad {
    background: #fee2e2;
    color: #991b1b;
}

#cpms-device-state .quality-unknown {
    background: #e5e7eb;
    color: #374151;
}

#cpms-device-state .muted {
    color: #64748b;
}
